#include <bits/stdc++.h>
using namespace std;
int d[8][2]={{1,2},{-1,2},{1,-2},{-1,-2},{2,1},{-2,1},{2,-1},{-2,-1}};
int n,m,x,y,step[402][402];
int main(){
    scanf("%d%d%d%d",&n,&m,&x,&y);
    queue<int> qx,qy;
    qx.push(x),qy.push(y);
    step[x][y]=1;
    while(qx.size()){
        int fx=qx.front(),fy=qy.front();
        qx.pop(),qy.pop();
        for(int i=0;i<8;i++){
            int xx=fx+d[i][0],yy=fy+d[i][1];
            if(xx>0 && yy>0 && xx<=n && yy<=m && !step[xx][yy])
                step[xx][yy]=step[fx][fy]+1,qx.push(xx),qy.push(yy);
        }
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++)
            printf("%d ",step[i][j]-1);
        printf("\n");
    }
    return 0;
}
